import React from 'react';

const NotesApp = () => {
  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center">
      <div className="bg-white p-6 rounded shadow-md w-full max-w-md">
        <h2 className="text-xl font-semibold mb-4">Catatan Anda</h2>
        <textarea className="w-full h-40 p-2 border rounded" placeholder="Tulis catatan di sini..."></textarea>
        <button className="mt-4 bg-blue-500 text-white py-2 px-4 rounded">Simpan Catatan</button>
      </div>
    </div>
  );
};

export default NotesApp;
